# Category: datastore_security

import os
import sys
import getpass
import argparse
import mysql.connector
from mysql.connector import errorcode

def validate_file(path: str) -> str:
    if not path:
        raise ValueError("Empty file path.")
    p = os.path.abspath(os.path.expanduser(path.strip()))
    if not os.path.isfile(p):
        raise FileNotFoundError(f"File not found: {p}")
    return p

def connect_mysql(host, port, user, password, database, allow_local_infile=True):
    cfg = {
        "host": host,
        "port": port,
        "user": user,
        "password": password,
        "database": database,
        "autocommit": False,
        "use_pure": True,
    }
    if allow_local_infile:
        cfg["allow_local_infile"] = True
    return mysql.connector.connect(**cfg)

def build_load_sql(file_path, table, columns=None, fields_terminated_by=",", fields_enclosed_by=None,
                   fields_escaped_by="\\", lines_terminated_by="\n", ignore_lines=0, charset=None,
                   local=True):
    infile_kw = "LOCAL INFILE" if local else "INFILE"
    fp = file_path.replace("\\", "\\\\").replace("'", "\\'")
    sql = "LOAD DATA {} '{}' INTO TABLE {}".format(infile_kw, fp, table)

    if charset:
        sql += " CHARACTER SET {}".format(charset)

    sql += " FIELDS TERMINATED BY '{}'".format(fields_terminated_by.replace("'", "\\'"))

    if fields_enclosed_by is not None and fields_enclosed_by != "":
        sql += " ENCLOSED BY '{}'".format(fields_enclosed_by.replace("'", "\\'"))

    if fields_escaped_by is not None and fields_escaped_by != "":
        sql += " ESCAPED BY '{}'".format(fields_escaped_by.replace("'", "\\'"))

    sql += " LINES TERMINATED BY '{}'".format(lines_terminated_by.replace("'", "\\'"))

    if ignore_lines and int(ignore_lines) > 0:
        sql += " IGNORE {} LINES".format(int(ignore_lines))

    if columns:
        cols = ",".join([c.strip() for c in columns.split(",") if c.strip()])
        if cols:
            sql += " ({})".format(cols)

    return sql

def ensure_local_infile_enabled(conn):
    cur = conn.cursor()
    cur.execute("SHOW VARIABLES LIKE 'local_infile'")
    row = cur.fetchone()
    cur.close()
    if not row:
        return
    val = str(row[1]).strip().lower()
    if val not in ("on", "1", "true", "yes"):
        raise RuntimeError("MySQL server variable local_infile is OFF. Enable it in MySQL config (local_infile=1) and restart server.")

def run_import(conn, sql):
    cur = conn.cursor()
    try:
        cur.execute(sql)
        affected = cur.rowcount
        conn.commit()
        return affected
    except Exception:
        conn.rollback()
        raise
    finally:
        cur.close()

def parse_args():
    ap = argparse.ArgumentParser(description="Bulk import into MySQL using LOAD DATA INFILE/LOCAL INFILE.")
    ap.add_argument("--host", default=os.environ.get("MYSQL_HOST", "127.0.0.1"))
    ap.add_argument("--port", type=int, default=int(os.environ.get("MYSQL_PORT", "3306")))
    ap.add_argument("--user", default=os.environ.get("MYSQL_USER", "root"))
    ap.add_argument("--password", default=os.environ.get("MYSQL_PASSWORD"))
    ap.add_argument("--database", default=os.environ.get("MYSQL_DATABASE"))
    ap.add_argument("--table", required=True)
    ap.add_argument("--file", action="append", dest="files", help="Path to file to import. Can be specified multiple times.")
    ap.add_argument("--prompt-files", action="store_true", help="Prompt for file paths interactively (one per line).")
    ap.add_argument("--columns", default=None, help="Comma-separated column list for LOAD DATA.")
    ap.add_argument("--fields-terminated-by", default=",")
    ap.add_argument("--fields-enclosed-by", default=None)
    ap.add_argument("--fields-escaped-by", default="\\")
    ap.add_argument("--lines-terminated-by", default="\n")
    ap.add_argument("--ignore-lines", type=int, default=0)
    ap.add_argument("--charset", default=None)
    ap.add_argument("--no-local", action="store_true", help="Use LOAD DATA INFILE (server-side) instead of LOCAL INFILE.")
    ap.add_argument("--skip-local-infile-check", action="store_true")
    return ap.parse_args()

def prompt_for_files():
    print("Enter file paths to import (one per line). Blank line to finish:", file=sys.stderr)
    paths = []
    while True:
        try:
            line = input().strip()
        except EOFError:
            break
        if not line:
            break
        paths.append(line)
    return paths

def main():
    args = parse_args()

    if not args.database:
        print("Error: --database is required (or set MYSQL_DATABASE).", file=sys.stderr)
        sys.exit(2)

    password = args.password
    if password is None:
        password = getpass.getpass("MySQL password: ")

    files = list(args.files or [])
    if args.prompt_files:
        files.extend(prompt_for_files())

    if not files:
        print("Error: No files provided. Use --file or --prompt-files.", file=sys.stderr)
        sys.exit(2)

    validated_files = []
    for f in files:
        try:
            validated_files.append(validate_file(f))
        except Exception as e:
            print(f"Error: {e}", file=sys.stderr)
            sys.exit(2)

    try:
        conn = connect_mysql(
            host=args.host,
            port=args.port,
            user=args.user,
            password=password,
            database=args.database,
            allow_local_infile=not args.no_local,
        )
    except mysql.connector.Error as err:
        if err.errno == errorcode.ER_ACCESS_DENIED_ERROR:
            print("Error: Access denied (check user/password).", file=sys.stderr)
        elif err.errno == errorcode.ER_BAD_DB_ERROR:
            print("Error: Database does not exist.", file=sys.stderr)
        else:
            print(f"Error: {err}", file=sys.stderr)
        sys.exit(1)

    try:
        if not args.skip_local_infile_check:
            ensure_local_infile_enabled(conn)

        total = 0
        for fp in validated_files:
            sql = build_load_sql(
                file_path=fp,
                table=args.table,
                columns=args.columns,
                fields_terminated_by=args.fields_terminated_by,
                fields_enclosed_by=args.fields_enclosed_by,
                fields_escaped_by=args.fields_escaped_by,
                lines_terminated_by=args.lines_terminated_by,
                ignore_lines=args.ignore_lines,
                charset=args.charset,
                local=not args.no_local,
            )
            affected = run_import(conn, sql)
            total += max(0, affected if affected is not None else 0)
            print(f"Imported file: {fp} -> table {args.table} (rowcount={affected})")
        print(f"Done. Total rowcount={total}")
    finally:
        try:
            conn.close()
        except Exception:
            pass

if __name__ == "__main__":
    main()